import{_ as e,f as s,k as a,N as n}from"./plugin-vue_export-helper.e5331ba5.js";const m='{"title":"\uBE4C\uB4DC&\uBC30\uD3EC","description":"","frontmatter":{},"headers":[{"level":2,"title":"\uBE4C\uB4DC","slug":"\uBE4C\uB4DC"},{"level":3,"title":"\uBBF8\uB9AC\uBCF4\uAE30","slug":"\uBBF8\uB9AC\uBCF4\uAE30"},{"level":2,"title":"\uBC30\uD3EC","slug":"\uBC30\uD3EC"},{"level":3,"title":"\uBC30\uD3EC","slug":"\uBC30\uD3EC-1"}],"relativePath":"guide/deploy.md","lastUpdated":1723014140914}',t={},p=n(`<h1 id="\uBE4C\uB4DC-\uBC30\uD3EC"><a class="header-anchor" href="#\uBE4C\uB4DC-\uBC30\uD3EC" aria-hidden="true">#</a> \uBE4C\uB4DC&amp;\uBC30\uD3EC</h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>\uC774 \uD504\uB85C\uC81D\uD2B8\uB294 \uC2DC\uC5F0\uC6A9\uC774\uAE30 \uB54C\uBB38\uC5D0 \uBE4C\uB4DC \uD6C4 \uD30C\uC77C \uD06C\uAE30\uAC00 \uC0C1\uB300\uC801\uC73C\uB85C \uD07D\uB2C8\uB2E4. \uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uC0AC\uC6A9\uD558\uC9C0 \uC54A\uB294 \uD50C\uB7EC\uADF8\uC778\uC740 \uD574\uB2F9 \uD30C\uC77C\uC774\uB098 \uB77C\uC6B0\uD2B8\uB97C \uC0AD\uC81C\uD558\uBA74 \uB429\uB2C8\uB2E4. \uC0AC\uC6A9\uD558\uC9C0 \uC54A\uC73C\uBA74 \uCC38\uC870\uB418\uC9C0 \uC54A\uC73C\uBBC0\uB85C \uBE4C\uB4DC \uC2DC \uD3EC\uD568\uB418\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.</p></div><h2 id="\uBE4C\uB4DC"><a class="header-anchor" href="#\uBE4C\uB4DC" aria-hidden="true">#</a> \uBE4C\uB4DC</h2><p>\uD504\uB85C\uC81D\uD2B8 \uAC1C\uBC1C\uC774 \uC644\uB8CC\uB41C \uD6C4, \uB2E4\uC74C \uBA85\uB839\uC5B4\uB97C \uC2E4\uD589\uD558\uC5EC \uBE4C\uB4DC\uB97C \uC218\uD589\uD569\uB2C8\uB2E4.</p><ul><li>\uAC1C\uBC1C \uD658\uACBD pnpm run build:dev ===&gt; dist-dev</li><li>\uD14C\uC2A4\uD2B8 \uD658\uACBD pnpm run build:test ===&gt; dist-test</li><li>\uC0DD\uC0B0 \uD658\uACBD pnpm run build:pro ===&gt; dist-pro</li></ul><p>\uBE4C\uB4DC\uAC00 \uC131\uACF5\uC801\uC73C\uB85C \uC644\uB8CC\uB418\uBA74, \uB8E8\uD2B8 \uB514\uB809\uD1A0\uB9AC\uC5D0 dist-* \uD3F4\uB354\uAC00 \uC0DD\uC131\uB418\uBA70, \uADF8 \uC548\uC5D0 \uBE4C\uB4DC\uB41C \uD30C\uC77C\uB4E4\uC774 \uD3EC\uD568\uB429\uB2C8\uB2E4.</p><h3 id="\uBBF8\uB9AC\uBCF4\uAE30"><a class="header-anchor" href="#\uBBF8\uB9AC\uBCF4\uAE30" aria-hidden="true">#</a> \uBBF8\uB9AC\uBCF4\uAE30</h3><p>\uBC30\uD3EC\uD558\uAE30 \uC804\uC5D0 \uB85C\uCEEC\uC5D0\uC11C \uBBF8\uB9AC\uBCF4\uAE30 \uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</p><p><strong>\uBE4C\uB4DC\uB41C HTML \uD30C\uC77C\uC744 \uC9C1\uC811 \uC5F4\uBA74 \uC548 \uB429\uB2C8\uB2E4.</strong></p><p>\uD504\uB85C\uC81D\uD2B8\uC5D0\uC11C \uC81C\uACF5\uD558\uB294 \uBA85\uB839\uC5B4\uB97C \uC0AC\uC6A9\uD558\uC5EC \uBBF8\uB9AC\uBCF4\uAE30(\uCD94\uCC9C)\uB97C \uC9C4\uD589\uD569\uB2C8\uB2E4.</p><div class="language-bash"><pre><code><span class="token comment"># \uBA3C\uC800 \uBE4C\uB4DC\uD55C \uD6C4 \uBBF8\uB9AC\uBCF4\uAE30</span>

<span class="token comment"># \uAC1C\uBC1C \uD658\uACBD \uBBF8\uB9AC\uBCF4\uAE30</span>
<span class="token function">pnpm</span> run serve:dev

<span class="token comment"># \uD14C\uC2A4\uD2B8 \uD658\uACBD \uBBF8\uB9AC\uBCF4\uAE30</span>
<span class="token function">pnpm</span> run serve:test

<span class="token comment"># pro \uD658\uACBD \uBBF8\uB9AC\uBCF4\uAE30</span>
<span class="token function">pnpm</span> run serve:pro
</code></pre></div><h2 id="\uBC30\uD3EC"><a class="header-anchor" href="#\uBC30\uD3EC" aria-hidden="true">#</a> \uBC30\uD3EC</h2><div class="danger custom-block"><p class="custom-block-title">\uC8FC\uC758</p><p>\uD504\uB85C\uC81D\uD2B8\uB294 \uAE30\uBCF8\uC801\uC73C\uB85C \uC0DD\uC0B0 \uD658\uACBD\uC5D0\uC11C Mock\uC774 \uD65C\uC131\uD654\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uB294 \uB370\uC774\uD130\uAC00 \uC788\uB294 \uC2DC\uC5F0 \uD658\uACBD\uC744 \uB9CC\uB4E4\uAE30 \uC704\uD55C \uAC83\uC73C\uB85C, \uC2E4\uC81C \uC0DD\uC0B0 \uD658\uACBD\uC5D0\uC11C\uB294 Mock\uC744 \uC0AC\uC6A9\uD558\uB294 \uAC83\uC774 \uC88B\uC9C0 \uC54A\uC73C\uBA70, \uC2E4\uC81C \uBC31\uC5D4\uB4DC API\uB97C \uC0AC\uC6A9\uD558\uB294 \uAC83\uC774 \uBC14\uB78C\uC9C1\uD569\uB2C8\uB2E4.</p></div><h3 id="\uBC30\uD3EC-1"><a class="header-anchor" href="#\uBC30\uD3EC-1" aria-hidden="true">#</a> \uBC30\uD3EC</h3><p>\uAC04\uB2E8\uD55C \uBC30\uD3EC\uB294 \uCD5C\uC885\uC801\uC73C\uB85C \uC0DD\uC131\uB41C \uC815\uC801 \uD30C\uC77C, \uC989 dist-* \uD3F4\uB354 \uB0B4\uC758 \uC815\uC801 \uD30C\uC77C\uC744 CDN \uB610\uB294 \uC815\uC801 \uC11C\uBC84\uC5D0 \uBC30\uD3EC\uD558\uB294 \uAC83\uC73C\uB85C \uCDA9\uBD84\uD569\uB2C8\uB2E4.</p><p><strong>\uBC30\uD3EC \uC911 \uB9AC\uC18C\uC2A4 \uACBD\uB85C\uAC00 \uC798\uBABB\uB41C \uAC83\uC744 \uBC1C\uACAC\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774 \uACBD\uC6B0, \uD574\uB2F9 <code>.env.xxx</code> \uD30C\uC77C\uC744 \uC218\uC815\uD558\uBA74 \uB429\uB2C8\uB2E4.\u3002</strong></p><div class="language-bash"><pre><code><span class="token comment"># \uC790\uC2E0\uC758 \uACBD\uB85C\uC5D0 \uB9DE\uAC8C \uC124\uC815\uC744 \uBCC0\uACBD\uD558\uC138\uC694</span>
VITE_BASE_PATH <span class="token operator">=</span> /dist-dev/
</code></pre></div>`,17),o=[p];function r(c,l,d,i,h,u){return a(),s("div",null,o)}var v=e(t,[["render",r]]);export{m as __pageData,v as default};
